+func yamlDiff(expected, generated string) (string, error) {
+	var expectedYAML interface{}
+	if err := yaml.Unmarshal([]byte(removeCommentLines(expected)), &expectedYAML); err != nil {
+		return "", fmt.Errorf("unmarshalling expected yaml: %w", err)
+	}
+
+	var generatedYAML interface{}
+	if err := yaml.Unmarshal([]byte(removeCommentLines(generated)), &generatedYAML); err != nil {
+		return "", fmt.Errorf("unmarshalling generated yaml: %w", err)
+	}
+
+	return cmp.Diff(expectedYAML, generatedYAML), nil
+}
+
+func removeCommentLines(in string) string {
+	lines := strings.Split(in, "\n")
+	out := make([]string, 0, len(lines))
+	for _, line := range lines {
+		if strings.HasPrefix(strings.TrimSpace(line), "#") {
+			continue
+		}
+
+		out = append(out, line)
+	}
+
+	return strings.Join(out, "\n")
+}
